export interface Product {
  /**
   * @displayName Product
   * @description Unique system identifier - GUID generated by system
   * @uiConstraints NEVER create input fields for this ID
   */
  id: string;
  /**
   * @displayName Product Name
   * @description Human-readable record identifier
   * @validationRule Required for create/update operations
   */
  productName: string;
  /**
   * @displayName Category
   * @validationRule Required for create/update operations
   */
  category: string;
  /**
   * @displayName Feature Highlight
   * @validationRule Required for create/update operations
   */
  featureHighlight: string;
  /**
   * @displayName Image URL
   * @validationRule Required for create/update operations
   */
  imageURL: string;
  /**
   * @displayName Product URL
   * @validationRule Required for create/update operations
   */
  productURL: string;
  /**
   * @displayName Sort Order
   * @validationRule Required for create/update operations
   */
  sortOrder: number;
  /**
   * @displayName Specification
   * @validationRule Required for create/update operations
   */
  specification: string;
  /**
   * @displayName Summary
   * @validationRule Required for create/update operations
   */
  summary: string;
}

export const _Product = 'Product' as const;